# explorer L2 S35 S35-T4-A-E2: lectura packet-only
def assess(record: dict) -> str:
    required = {"case_id", "use", "out_of_scope", "contestability"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = record["use"] == "queue_rank" and "fraud_label" in record["out_of_scope"] and record["contestability"] is True
    return "PASS" if ok else "REJECT_SCOPE_BREACH"

valid = {"case_id": "CASO-LIM-035-4A", **{'use': 'queue_rank', 'out_of_scope': ['fraud_label'], 'contestability': True}}
invalid = {"case_id": "CASO-LIM-035-4A", **{'use': 'fraud_label', 'out_of_scope': [], 'contestability': True}}
incomplete = {k: v for k, v in valid.items() if k != "out_of_scope"}
print(assess(valid), assess(invalid), assess(incomplete))

